Prompt(promptCliente,&EmpCod,&CreCliCod);

Prompt(promptVendedor,&EmpCod,&CreVenCod);

Event Start
/* Generated by DVelop Work With Plus Pattern [Start] - Do not change */
&IsPrometidas.TooltipText = "Procura todas as duplicatas do período do vencimento porém filtrando a data de promessa"
&EmpCod.Visible = False &PadObs.Visible = False
Grid.Rows = Page.Rows Grid_Empowerer.GridInternalName = Grid.InternalName
JSDynamicFilters.Caption = '' &DynamicFiltersSelector1 = !'CREDUPNRO' Do 'EnableDynamicFilters1' &DynamicFiltersSelector2 = !'CREDUPNRO' Do 'EnableDynamicFilters2' &DynamicFiltersSelector3 = !'CREDUPNRO' Do 'EnableDynamicFilters3'
AddDynamicFilters1.JSEvent('onclick', format(!"WWPDynFilterShow_AL('%1', 2, 2)", TableDynamicFilters.InternalName)) RemoveDynamicFilters1.JSEvent('onclick', format(!"WWPDynFilterHideLast_AL('%1', 3, 2)", TableDynamicFilters.InternalName)) AddDynamicFilters2.JSEvent('onclick', format(!"WWPDynFilterShow_AL('%1', 3, 2)", TableDynamicFilters.InternalName)) RemoveDynamicFilters2.JSEvent('onclick', format(!"WWPDynFilterHideLast_AL('%1', 3, 2)", TableDynamicFilters.InternalName)) RemoveDynamicFilters3.JSEvent('onclick', format(!"WWPDynFilterHideLast_AL('%1', 3, 2)", TableDynamicFilters.InternalName)) &CreRecPag = nullvalue(&CreRecPag) &CreSts = nullvalue(&CreSts) &CreFrpPgtoTip = nullvalue(&CreFrpPgtoTip) DDO_Grid.GridInternalName = Grid.InternalName Form.Caption = ' Cobrança Duplicatas'
Do 'PrepareTransaction' Do 'LoadGridState' If &OrderedBy < 1 &OrderedBy = 1 Do 'SetDDOSortedStatus' EndIf WCCobrancaCobrancas.Object = CobrancaCobrancas.Create(EmpCod, FilCod, CreCod) WCCobrancaPagamentos.Object = CobrancaPagamentos.Create(EmpCod, FilCod, CreCod) &DDO_TitleSettingsIcons = GetWWPTitleSettingsIcons() GridPaginationBar.RowsPerPageSelectedValue = Grid.Rows
/* Generated by DVelop Work With Plus Pattern [End] - Do not change */
EndEvent
Event Refresh
retornaAutorizacao.Call('WWCOBRANCA', Status_SimNao.Sim, 1, &AutNiv) LoadWWPContext.Call(&Context)
&EmpCod = &Context.EmpCod
If &Context.PesIsVen = true retornaAutorizacao.Call('TELEVENDATROCARVENDEDOR', Status_SimNao.Nao, 1, &AutNivTel) If &AutNivTel = 0 &CreVenCod = &Context.PesCod &CreVenCod.Enabled = 0 // Do 'Vendedor' Else &CreVenCod.Enabled = 1 EndIf EndIF
padraoUsuario.call('L', &Pgmname, &Context.PesCod, &Context.EmpCod, &padObs, &PadDtaMod)
If &PadObs.IsEmpty() &IsCobHoje = false &IsPrometidas = False &CreDtaCob_To.Enabled = false &CreDtaCob.Enabled = False Else &IsPrometidas = iif(Substr(&padObs,1,1) = 'S', true, false) &IsCobHoje = iif(Substr(&padObs,2,1) = 'S', true, false) EndIF
&Hoje = ServerDate() &CreDtaVct = Iif(&CreDtaVct_To.IsEmpty(),&Hoje,&CreDtaVct) &CreDtaVct_To = Iif(&CreDtaVct_To.IsEmpty(),&Hoje,&CreDtaVct_To) &CreDtaCob_To = Iif(&CreDtaCob_To.IsEmpty(),&Hoje,&CreDtaCob_To)
&HjCreDtaCob = &Hoje -1
/* Generated by DVelop Work With Plus Pattern [Start] - Do not change */
LoadWWPContext.Call(&Context)
&DynamicFiltersOperator1.Clear() Do Case Case &DynamicFiltersSelector1 = !'CREDUPNRO' &DynamicFiltersOperator1.AddItem(0, "Começa com") &DynamicFiltersOperator1.AddItem(1, "Contém") Case &DynamicFiltersSelector1 = !'CRECLIRAZ' &DynamicFiltersOperator1.AddItem(0, "Começa com") &DynamicFiltersOperator1.AddItem(1, "Contém") Case &DynamicFiltersSelector1 = !'CRECBRNOM' &DynamicFiltersOperator1.AddItem(0, "Começa com") &DynamicFiltersOperator1.AddItem(1, "Contém") EndCase If &DynamicFiltersEnabled2 &DynamicFiltersOperator2.Clear() Do Case Case &DynamicFiltersSelector2 = !'CREDUPNRO' &DynamicFiltersOperator2.AddItem(0, "Começa com") &DynamicFiltersOperator2.AddItem(1, "Contém") Case &DynamicFiltersSelector2 = !'CRECLIRAZ' &DynamicFiltersOperator2.AddItem(0, "Começa com") &DynamicFiltersOperator2.AddItem(1, "Contém") Case &DynamicFiltersSelector2 = !'CRECBRNOM' &DynamicFiltersOperator2.AddItem(0, "Começa com") &DynamicFiltersOperator2.AddItem(1, "Contém") EndCase If &DynamicFiltersEnabled3 &DynamicFiltersOperator3.Clear() Do Case Case &DynamicFiltersSelector3 = !'CREDUPNRO' &DynamicFiltersOperator3.AddItem(0, "Começa com") &DynamicFiltersOperator3.AddItem(1, "Contém") Case &DynamicFiltersSelector3 = !'CRECLIRAZ' &DynamicFiltersOperator3.AddItem(0, "Começa com") &DynamicFiltersOperator3.AddItem(1, "Contém") Case &DynamicFiltersSelector3 = !'CRECBRNOM' &DynamicFiltersOperator3.AddItem(0, "Começa com") &DynamicFiltersOperator3.AddItem(1, "Contém") EndCase EndIf EndIf Do 'SaveGridState'
&GridCurrentPage = Grid.CurrentPage &GridPageCount = Grid.PageCount
/* Generated by DVelop Work With Plus Pattern [End] - Do not change */
EndEvent
Event GridPaginationBar.ChangePage
/* Generated by DVelop Work With Plus Pattern [Start] - Do not change */
Do Case Case GridPaginationBar.SelectedPage = !'Previous' Grid.PreviousPage() Case GridPaginationBar.SelectedPage = !'Next' Grid.NextPage() Otherwise &PageToGo.FromString(GridPaginationBar.SelectedPage) Grid.GotoPage(&PageToGo) EndCase
/* Generated by DVelop Work With Plus Pattern [End] - Do not change */
EndEvent
Event GridPaginationBar.ChangeRowsPerPage
/* Generated by DVelop Work With Plus Pattern [Start] - Do not change */
Grid.Rows = GridPaginationBar.RowsPerPageSelectedValue Grid.FirstPage()
/* Generated by DVelop Work With Plus Pattern [End] - Do not change */
EndEvent
Event DDO_Grid.OnOptionClicked
/* Generated by DVelop Work With Plus Pattern [Start] - Do not change */
Do Case Case DDO_Grid.ActiveEventKey = !'<#OrderASC#>' OR DDO_Grid.ActiveEventKey = !'<#OrderDSC#>' &OrderedBy.FromString(DDO_Grid.SelectedValue_get) &OrderedDsc = iif(DDO_Grid.ActiveEventKey = !'<#OrderDSC#>', true, false) Do 'SetDDOSortedStatus' Grid.FirstPage() EndCase
/* Generated by DVelop Work With Plus Pattern [End] - Do not change */
EndEvent
Event Grid.Load
/* Generated by DVelop Work With Plus Pattern [Start] - Do not change */
&Cobrar.FromImage(ActionCopyRecord) &Cobrar.TooltipText = "Cobrar Cliente"
/* Generated by DVelop Work With Plus Pattern [End] - Do not change */
CreDupNro.Link = VerDuplicata.Link('wwCobranca', EmpCod, FilCod, CreCod)
CreVenCod.Link = VerCliente.Link('WWCobranca', EmpCod,CreVenCod) CreVenCod.Tooltiptext = CreVenNom.Trim()
CreCbrCod.Tooltiptext = CreCbrNom.Trim()
&Cobrar.Link = WWCobrar.LInk(TrnMode.Insert,EmpCod,FilCod,CreCod) &CreCliCodRaz = substr(CreCliCodRaz, 1,50)
&CreCliCodRaz.Link = VerCliente.Link('WWCobranca', EmpCod, CreCliCod)
CrePedCod.Link = VerPedido.Link('WWCobranca', EmpCod, FilCod, CrePedCod)
EndEvent
Event 'AddDynamicFilters1'
/* Generated by DVelop Work With Plus Pattern [Start] - Do not change */
&DynamicFiltersEnabled2 = True AddDynamicFilters1.Visible = False RemoveDynamicFilters1.Visible = True Grid.Refresh()
/* Generated by DVelop Work With Plus Pattern [End] - Do not change */
EndEvent
Event 'RemoveDynamicFilters1'
/* Generated by DVelop Work With Plus Pattern [Start] - Do not change */
&DynamicFiltersRemoving = True &DynamicFiltersIgnoreFirst = True Do 'SaveDynFiltersState' Do 'ResetDynFilters' Do 'LoadDynFiltersState' &DynamicFiltersRemoving = False &DynamicFiltersIgnoreFirst = False Grid.Refresh()
/* Generated by DVelop Work With Plus Pattern [End] - Do not change */
EndEvent
Event &DynamicFiltersSelector1.Click
/* Generated by DVelop Work With Plus Pattern [Start] - Do not change */
&DynamicFiltersOperator1.SetEmpty() Do 'EnableDynamicFilters1'
/* Generated by DVelop Work With Plus Pattern [End] - Do not change */
EndEvent
Event 'AddDynamicFilters2'
/* Generated by DVelop Work With Plus Pattern [Start] - Do not change */
&DynamicFiltersEnabled3 = True AddDynamicFilters2.Visible = False RemoveDynamicFilters2.Visible = True Grid.Refresh()
/* Generated by DVelop Work With Plus Pattern [End] - Do not change */
EndEvent
Event 'RemoveDynamicFilters2'
/* Generated by DVelop Work With Plus Pattern [Start] - Do not change */
&DynamicFiltersRemoving = True &DynamicFiltersEnabled2 = False Do 'SaveDynFiltersState' Do 'ResetDynFilters' Do 'LoadDynFiltersState' &DynamicFiltersRemoving = False Grid.Refresh()
/* Generated by DVelop Work With Plus Pattern [End] - Do not change */
EndEvent
Event &DynamicFiltersSelector2.Click
/* Generated by DVelop Work With Plus Pattern [Start] - Do not change */
&DynamicFiltersOperator2.SetEmpty() Do 'EnableDynamicFilters2'
/* Generated by DVelop Work With Plus Pattern [End] - Do not change */
EndEvent
Event 'RemoveDynamicFilters3'
/* Generated by DVelop Work With Plus Pattern [Start] - Do not change */
&DynamicFiltersRemoving = True &DynamicFiltersEnabled3 = False Do 'SaveDynFiltersState' Do 'ResetDynFilters' Do 'LoadDynFiltersState' &DynamicFiltersRemoving = False Grid.Refresh()
/* Generated by DVelop Work With Plus Pattern [End] - Do not change */
EndEvent
Event &DynamicFiltersSelector3.Click
/* Generated by DVelop Work With Plus Pattern [Start] - Do not change */
&DynamicFiltersOperator3.SetEmpty() Do 'EnableDynamicFilters3'
/* Generated by DVelop Work With Plus Pattern [End] - Do not change */
EndEvent
Event 'DoHistorico'
/* Generated by DVelop Work With Plus Pattern [Start] - Do not change */
WWHistoricoCliente.Call(CreCliCod)
/* Generated by DVelop Work With Plus Pattern [End] - Do not change */
EndEvent
Event 'DoExport'
/* Generated by DVelop Work With Plus Pattern [Start] - Do not change */
// Generate Excel spreadsheet and download it. Do 'LoadGridState' ExportWWCobranca.Call(&ExcelFilename, &ErrorMessage) If (&ExcelFilename <> "") Link(&ExcelFilename) Else msg(&ErrorMessage) Endif
/* Generated by DVelop Work With Plus Pattern [End] - Do not change */
EndEvent
Event 'DoExportReport'
/* Generated by DVelop Work With Plus Pattern [Start] - Do not change */
// Generate PDF file. Do 'LoadGridState' InNewWindow1.Target = ExportReportWWCobranca.Link() InNewWindow1.Height = !'600' InNewWindow1.Width = !'800' InNewWindow1.OpenWindow()
/* Generated by DVelop Work With Plus Pattern [End] - Do not change */
EndEvent
Sub 'SetDDOSortedStatus'
/* Generated by DVelop Work With Plus Pattern [Start] - Do not change */
DDO_Grid.SortedStatus = &OrderedBy.ToString().Trim() + !':' + iif(&OrderedDsc, !'DSC', !'ASC')
/* Generated by DVelop Work With Plus Pattern [End] - Do not change */
EndSub
Sub 'EnableDynamicFilters1'
/* Generated by DVelop Work With Plus Pattern [Start] - Do not change */
&CreDupNro1.Visible = False &CreCliRaz1.Visible = False &CreCbrNom1.Visible = False &CreCbrCod1.Visible = False &DynamicFiltersOperator1.Visible = False Do Case Case &DynamicFiltersSelector1 = !'CREDUPNRO' &CreDupNro1.Visible = True &DynamicFiltersOperator1.Visible = True Case &DynamicFiltersSelector1 = !'CRECLIRAZ' &CreCliRaz1.Visible = True &DynamicFiltersOperator1.Visible = True Case &DynamicFiltersSelector1 = !'CRECBRNOM' &CreCbrNom1.Visible = True &DynamicFiltersOperator1.Visible = True Case &DynamicFiltersSelector1 = !'CRECBRCOD' &CreCbrCod1.Visible = True EndCase
/* Generated by DVelop Work With Plus Pattern [End] - Do not change */
EndSub
Sub 'EnableDynamicFilters2'
/* Generated by DVelop Work With Plus Pattern [Start] - Do not change */
&CreDupNro2.Visible = False &CreCliRaz2.Visible = False &CreCbrNom2.Visible = False &CreCbrCod2.Visible = False &DynamicFiltersOperator2.Visible = False Do Case Case &DynamicFiltersSelector2 = !'CREDUPNRO' &CreDupNro2.Visible = True &DynamicFiltersOperator2.Visible = True Case &DynamicFiltersSelector2 = !'CRECLIRAZ' &CreCliRaz2.Visible = True &DynamicFiltersOperator2.Visible = True Case &DynamicFiltersSelector2 = !'CRECBRNOM' &CreCbrNom2.Visible = True &DynamicFiltersOperator2.Visible = True Case &DynamicFiltersSelector2 = !'CRECBRCOD' &CreCbrCod2.Visible = True EndCase
/* Generated by DVelop Work With Plus Pattern [End] - Do not change */
EndSub
Sub 'EnableDynamicFilters3'
/* Generated by DVelop Work With Plus Pattern [Start] - Do not change */
&CreDupNro3.Visible = False &CreCliRaz3.Visible = False &CreCbrNom3.Visible = False &CreCbrCod3.Visible = False &DynamicFiltersOperator3.Visible = False Do Case Case &DynamicFiltersSelector3 = !'CREDUPNRO' &CreDupNro3.Visible = True &DynamicFiltersOperator3.Visible = True Case &DynamicFiltersSelector3 = !'CRECLIRAZ' &CreCliRaz3.Visible = True &DynamicFiltersOperator3.Visible = True Case &DynamicFiltersSelector3 = !'CRECBRNOM' &CreCbrNom3.Visible = True &DynamicFiltersOperator3.Visible = True Case &DynamicFiltersSelector3 = !'CRECBRCOD' &CreCbrCod3.Visible = True EndCase
/* Generated by DVelop Work With Plus Pattern [End] - Do not change */
EndSub
Sub 'ResetDynFilters'
/* Generated by DVelop Work With Plus Pattern [Start] - Do not change */
&DynamicFiltersEnabled2 = False &DynamicFiltersSelector2 = !'CREDUPNRO' &DynamicFiltersOperator2 = 0 &CreDupNro2.SetEmpty() Do 'EnableDynamicFilters2'
&DynamicFiltersEnabled3 = False &DynamicFiltersSelector3 = !'CREDUPNRO' &DynamicFiltersOperator3 = 0 &CreDupNro3.SetEmpty() Do 'EnableDynamicFilters3'
/* Generated by DVelop Work With Plus Pattern [End] - Do not change */
EndSub
Sub 'LoadGridState'
/* Generated by DVelop Work With Plus Pattern [Start] - Do not change */
// Load grid state from session. If &Session.Get(&PgmName + !"GridState") = !"" &GridState.FromXml(LoadGridState.Udp(&PgmName + !"GridState")) Else &GridState.FromXml(&Session.Get(&PgmName + !"GridState")) Endif
&OrderedBy = &GridState.OrderedBy &OrderedDsc = &GridState.OrderedDsc Do 'SetDDOSortedStatus'
For &GridStateFilterValue in &GridState.FilterValues Do Case Case &GridStateFilterValue.Name = !"CRECLICOD" &CreCliCod.FromString(&GridStateFilterValue.Value) Case &GridStateFilterValue.Name = !"CREVENCOD" &CreVenCod.FromString(&GridStateFilterValue.Value) Case &GridStateFilterValue.Name = !"CRERECPAG" &CreRecPag.FromString(&GridStateFilterValue.Value) Case &GridStateFilterValue.Name = !"CREVLRSDO" &CreVlrSdo.FromString(&GridStateFilterValue.Value) Case &GridStateFilterValue.Name = !"CRESTS" &CreSts.FromString(&GridStateFilterValue.Value) Case &GridStateFilterValue.Name = !"CREFRPPGTOTIP" &CreFrpPgtoTip.FromString(&GridStateFilterValue.Value) Case &GridStateFilterValue.Name = !"CREDTAVCT" &CreDtaVct.FromString(&GridStateFilterValue.Value) &CreDtaVct_To.FromString(&GridStateFilterValue.ValueTo) Case &GridStateFilterValue.Name = !"CREDTACOB" &CreDtaCob.FromString(&GridStateFilterValue.Value) &CreDtaCob_To.FromString(&GridStateFilterValue.ValueTo) EndCase EndFor Do 'LoadDynFiltersState' If not &GridState.PageSize.Trim().IsEmpty() Grid.Rows = &GridState.PageSize.ToNumeric() EndIf Grid.CurrentPage = &GridState.CurrentPage
/* Generated by DVelop Work With Plus Pattern [End] - Do not change */
EndSub
Sub 'LoadDynFiltersState'
/* Generated by DVelop Work With Plus Pattern [Start] - Do not change */
AddDynamicFilters1.Visible = True RemoveDynamicFilters1.Visible = False AddDynamicFilters2.Visible = True RemoveDynamicFilters2.Visible = False
If &GridState.DynamicFilters.Count >= 1 &GridStateDynamicFilter = &GridState.DynamicFilters.Item(1) &DynamicFiltersSelector1 = &GridStateDynamicFilter.Selected Do Case Case &DynamicFiltersSelector1 = !'CREDUPNRO' &DynamicFiltersOperator1 = &GridStateDynamicFilter.Operator &CreDupNro1.FromString(&GridStateDynamicFilter.Value) Case &DynamicFiltersSelector1 = !'CRECLIRAZ' &DynamicFiltersOperator1 = &GridStateDynamicFilter.Operator &CreCliRaz1.FromString(&GridStateDynamicFilter.Value) Case &DynamicFiltersSelector1 = !'CRECBRNOM' &DynamicFiltersOperator1 = &GridStateDynamicFilter.Operator &CreCbrNom1.FromString(&GridStateDynamicFilter.Value) Case &DynamicFiltersSelector1 = !'CRECBRCOD' &CreCbrCod1.FromString(&GridStateDynamicFilter.Value) EndCase Do 'EnableDynamicFilters1' If &GridState.DynamicFilters.Count >= 2 JSDynamicFilters.Caption = !'<script type="text/javascript">$(document).ready(function() {' JSDynamicFilters.Caption += format(!"WWPDynFilterShow_AL('%1', 2, 2);", TableDynamicFilters.InternalName) AddDynamicFilters1.Visible = False RemoveDynamicFilters1.Visible = True &DynamicFiltersEnabled2 = True &GridStateDynamicFilter = &GridState.DynamicFilters.Item(2) &DynamicFiltersSelector2 = &GridStateDynamicFilter.Selected Do Case Case &DynamicFiltersSelector2 = !'CREDUPNRO' &DynamicFiltersOperator2 = &GridStateDynamicFilter.Operator &CreDupNro2.FromString(&GridStateDynamicFilter.Value) Case &DynamicFiltersSelector2 = !'CRECLIRAZ' &DynamicFiltersOperator2 = &GridStateDynamicFilter.Operator &CreCliRaz2.FromString(&GridStateDynamicFilter.Value) Case &DynamicFiltersSelector2 = !'CRECBRNOM' &DynamicFiltersOperator2 = &GridStateDynamicFilter.Operator &CreCbrNom2.FromString(&GridStateDynamicFilter.Value) Case &DynamicFiltersSelector2 = !'CRECBRCOD' &CreCbrCod2.FromString(&GridStateDynamicFilter.Value) EndCase Do 'EnableDynamicFilters2' If &GridState.DynamicFilters.Count >= 3 JSDynamicFilters.Caption += format(!"WWPDynFilterShow_AL('%1', 3, 2);", TableDynamicFilters.InternalName) AddDynamicFilters2.Visible = False RemoveDynamicFilters2.Visible = True &DynamicFiltersEnabled3 = True &GridStateDynamicFilter = &GridState.DynamicFilters.Item(3) &DynamicFiltersSelector3 = &GridStateDynamicFilter.Selected Do Case Case &DynamicFiltersSelector3 = !'CREDUPNRO' &DynamicFiltersOperator3 = &GridStateDynamicFilter.Operator &CreDupNro3.FromString(&GridStateDynamicFilter.Value) Case &DynamicFiltersSelector3 = !'CRECLIRAZ' &DynamicFiltersOperator3 = &GridStateDynamicFilter.Operator &CreCliRaz3.FromString(&GridStateDynamicFilter.Value) Case &DynamicFiltersSelector3 = !'CRECBRNOM' &DynamicFiltersOperator3 = &GridStateDynamicFilter.Operator &CreCbrNom3.FromString(&GridStateDynamicFilter.Value) Case &DynamicFiltersSelector3 = !'CRECBRCOD' &CreCbrCod3.FromString(&GridStateDynamicFilter.Value) EndCase Do 'EnableDynamicFilters3' EndIf JSDynamicFilters.Caption += !'});</script>' EndIf EndIf If &DynamicFiltersRemoving JSDynamicFilters.Caption = '' EndIf
/* Generated by DVelop Work With Plus Pattern [End] - Do not change */
EndSub
Sub 'SaveGridState'
/* Generated by DVelop Work With Plus Pattern [Start] - Do not change */
&GridState.FromXml(&Session.Get(&PgmName + !"GridState"))
// Save grid state in session. &GridState.OrderedBy = &OrderedBy &GridState.OrderedDsc = &OrderedDsc &GridState.FilterValues.Clear() WWP_GridStateAddFilterValue(&GridState, !"CRECLICOD", "", not &CreCliCod.IsEmpty(), 0, &CreCliCod.ToString().Trim(), '') WWP_GridStateAddFilterValue(&GridState, !"CREVENCOD", "", not &CreVenCod.IsEmpty(), 0, &CreVenCod.ToString().Trim(), '') WWP_GridStateAddFilterValue(&GridState, !"CRERECPAG", "", not &CreRecPag.IsEmpty(), 0, &CreRecPag, '') WWP_GridStateAddFilterValue(&GridState, !"CREVLRSDO", "", not &CreVlrSdo.IsEmpty(), 0, &CreVlrSdo.ToString().Trim(), '') WWP_GridStateAddFilterValue(&GridState, !"CRESTS", "", not &CreSts.IsEmpty(), 0, &CreSts, '') WWP_GridStateAddFilterValue(&GridState, !"CREFRPPGTOTIP", "", not &CreFrpPgtoTip.IsEmpty(), 0, &CreFrpPgtoTip, '') WWP_GridStateAddFilterValue(&GridState, !"CREDTAVCT", "", not (&CreDtaVct.IsEmpty() AND &CreDtaVct_To.IsEmpty()), 0, &CreDtaVct.ToString().Trim(), &CreDtaVct_To.ToString().Trim()) WWP_GridStateAddFilterValue(&GridState, !"CREDTACOB", "", not (&CreDtaCob.IsEmpty() AND &CreDtaCob_To.IsEmpty()), 0, &CreDtaCob.ToString().Trim(), &CreDtaCob_To.ToString().Trim())
Do 'SaveDynFiltersState'
&GridState.PageSize = str(Grid.Rows) &GridState.CurrentPage = Grid.CurrentPage SaveGridState.Call(&PgmName + !"GridState", &GridState.ToXml())
/* Generated by DVelop Work With Plus Pattern [End] - Do not change */
EndSub
Sub 'SaveDynFiltersState'
/* Generated by DVelop Work With Plus Pattern [Start] - Do not change */
&GridState.DynamicFilters.Clear() If not &DynamicFiltersIgnoreFirst &GridStateDynamicFilter = new() &GridStateDynamicFilter.Selected = &DynamicFiltersSelector1 Do Case Case &DynamicFiltersSelector1 = !'CREDUPNRO' AND not &CreDupNro1.IsEmpty() &GridStateDynamicFilter.Value = &CreDupNro1.ToString() &GridStateDynamicFilter.Operator = &DynamicFiltersOperator1 Case &DynamicFiltersSelector1 = !'CRECLIRAZ' AND not &CreCliRaz1.IsEmpty() &GridStateDynamicFilter.Value = &CreCliRaz1.ToString() &GridStateDynamicFilter.Operator = &DynamicFiltersOperator1 Case &DynamicFiltersSelector1 = !'CRECBRNOM' AND not &CreCbrNom1.IsEmpty() &GridStateDynamicFilter.Value = &CreCbrNom1.ToString() &GridStateDynamicFilter.Operator = &DynamicFiltersOperator1 Case &DynamicFiltersSelector1 = !'CRECBRCOD' AND not &CreCbrCod1.IsEmpty() &GridStateDynamicFilter.Value = &CreCbrCod1.ToString() EndCase If &DynamicFiltersRemoving OR not &GridStateDynamicFilter.Value.IsEmpty() &GridState.DynamicFilters.Add(&GridStateDynamicFilter) EndIf EndIf If &DynamicFiltersEnabled2 &GridStateDynamicFilter = new() &GridStateDynamicFilter.Selected = &DynamicFiltersSelector2 Do Case Case &DynamicFiltersSelector2 = !'CREDUPNRO' AND not &CreDupNro2.IsEmpty() &GridStateDynamicFilter.Value = &CreDupNro2.ToString() &GridStateDynamicFilter.Operator = &DynamicFiltersOperator2 Case &DynamicFiltersSelector2 = !'CRECLIRAZ' AND not &CreCliRaz2.IsEmpty() &GridStateDynamicFilter.Value = &CreCliRaz2.ToString() &GridStateDynamicFilter.Operator = &DynamicFiltersOperator2 Case &DynamicFiltersSelector2 = !'CRECBRNOM' AND not &CreCbrNom2.IsEmpty() &GridStateDynamicFilter.Value = &CreCbrNom2.ToString() &GridStateDynamicFilter.Operator = &DynamicFiltersOperator2 Case &DynamicFiltersSelector2 = !'CRECBRCOD' AND not &CreCbrCod2.IsEmpty() &GridStateDynamicFilter.Value = &CreCbrCod2.ToString() EndCase If &DynamicFiltersRemoving OR not &GridStateDynamicFilter.Value.IsEmpty() &GridState.DynamicFilters.Add(&GridStateDynamicFilter) EndIf EndIf If &DynamicFiltersEnabled3 &GridStateDynamicFilter = new() &GridStateDynamicFilter.Selected = &DynamicFiltersSelector3 Do Case Case &DynamicFiltersSelector3 = !'CREDUPNRO' AND not &CreDupNro3.IsEmpty() &GridStateDynamicFilter.Value = &CreDupNro3.ToString() &GridStateDynamicFilter.Operator = &DynamicFiltersOperator3 Case &DynamicFiltersSelector3 = !'CRECLIRAZ' AND not &CreCliRaz3.IsEmpty() &GridStateDynamicFilter.Value = &CreCliRaz3.ToString() &GridStateDynamicFilter.Operator = &DynamicFiltersOperator3 Case &DynamicFiltersSelector3 = !'CRECBRNOM' AND not &CreCbrNom3.IsEmpty() &GridStateDynamicFilter.Value = &CreCbrNom3.ToString() &GridStateDynamicFilter.Operator = &DynamicFiltersOperator3 Case &DynamicFiltersSelector3 = !'CRECBRCOD' AND not &CreCbrCod3.IsEmpty() &GridStateDynamicFilter.Value = &CreCbrCod3.ToString() EndCase If &DynamicFiltersRemoving OR not &GridStateDynamicFilter.Value.IsEmpty() &GridState.DynamicFilters.Add(&GridStateDynamicFilter) EndIf EndIf
/* Generated by DVelop Work With Plus Pattern [End] - Do not change */
EndSub
Sub 'PrepareTransaction'
/* Generated by DVelop Work With Plus Pattern [Start] - Do not change */
&TrnContext = new() &TrnContext.CallerObject = &Pgmname &TrnContext.CallerOnDelete = True &TrnContext.CallerURL = &HTTPRequest.ScriptName + !"?" + &HTTPRequest.QueryString &TrnContext.TransactionName = !"Cobranca"
&Session.Set(!"TrnContext", &TrnContext.ToXml())
/* Generated by DVelop Work With Plus Pattern [End] - Do not change */
EndSub
Event &IsPrometidas.Click
do 'GravaFiltro'
EndEvent
Event &IsCobHoje.Click
If &IsCobHoje = true &CreDtaCob_To.Enabled = true &CreDtaCob.Enabled = true Else &CreDtaCob_To.Enabled = false &CreDtaCob.Enabled = False EndIf do 'GravaFiltro'
EndEvent
Event Grid.OnLineActivate
WCCobrancaCobrancas.Object = CobrancaCobrancas.Create(EmpCod, FilCod, CreCod) WCCobrancaPagamentos.Object = CobrancaPagamentos.Create(EmpCod, FilCod, CreCod)
EndEvent
Sub 'GravaFiltro'
&PadObs = IIF(&IsPrometidas = true,'S','N') &PadObs += IIF(&IsCobHoje = true,'S','N')
padraoUsuario.Call('G', &Pgmname, &Context.PesCod, &Context.EmpCod, &PadObs, &PadDtaMod)
EndSub
